    <script>
    // Scroll Animations
    const observer=new IntersectionObserver(e=>{e.forEach((t,i)=>{t.isIntersecting&&setTimeout(()=>t.target.classList.add('visible'),i*100)})},{threshold:0.1});
    document.querySelectorAll('.service-card,.tech-card,.portfolio-card,.testimonial-card').forEach(e=>observer.observe(e));

    // Smooth scroll
    document.querySelectorAll('a[href^="#"]').forEach(a=>{a.addEventListener('click',function(e){e.preventDefault();const t=document.querySelector(this.getAttribute('href'));if(t){const o=t.getBoundingClientRect().top+window.pageYOffset-80;window.scrollTo({top:o,behavior:'smooth'})}})});

    // Counter animation
    const stats=document.querySelectorAll('.stat-number');
    const statsObs=new IntersectionObserver(e=>{e.forEach(t=>{if(t.isIntersecting){const e=t.target,n=e.textContent,i=n.includes('%'),s=n.includes('+'),o=parseInt(n.replace(/[^0-9]/g,''));let r=0;const a=o/60;const u=()=>{r+=a;r<o?(e.textContent=Math.floor(r)+(s?'+':'')+(i?'%':''),requestAnimationFrame(u)):e.textContent=n};u();statsObs.unobserve(e)}})},{threshold:0.5});
    stats.forEach(s=>statsObs.observe(s));

    // Typing effect
    const tagline=document.querySelector('.hero-tagline');
    if(tagline){const t=tagline.textContent;tagline.textContent='';let i=0;setTimeout(()=>{const n=setInterval(()=>{i<t.length?tagline.textContent+=t.charAt(i++):clearInterval(n)},80)},500)}

    // Reveal on load
    window.addEventListener('load',()=>{document.querySelectorAll('.hero-content > *').forEach((e,i)=>{e.style.opacity='0';e.style.transform='translateY(20px)';e.style.transition='opacity 0.6s ease, transform 0.6s ease';setTimeout(()=>{e.style.opacity='1';e.style.transform='translateY(0)'},200+i*100)})});

    // Section headers reveal
    const hObs=new IntersectionObserver(e=>{e.forEach(t=>{t.isIntersecting&&(t.target.style.opacity='1',t.target.style.transform='translateY(0)')})},{threshold:0.2});
    document.querySelectorAll('.section-header').forEach(h=>{h.style.opacity='0';h.style.transform='translateY(30px)';h.style.transition='opacity 0.6s ease, transform 0.6s ease';hObs.observe(h)});
    </script>
